function solve(n) {
    // Map to store sum -> count of representations
    const sumCounts = new Map();

    // Helper function for cube calculation
    // Since n <= 10^9, standard JS number type is sufficient for intermediate cubes and sums.
    const cube = (k) => k * k * k;

    // Iterate through possible values of a, starting from 1
    for (let a = 1; ; a++) {
        const a_cubed = cube(a);

        // Optimization: If 2 * a^3 > n, then even a=b case exceeds n. Stop outer loop.
        if (2 * a_cubed > n) {
            break;
        }

        // Iterate through possible values of b, starting from a (since a <= b)
        for (let b = a; ; b++) {
            const b_cubed = cube(b);
            const x = a_cubed + b_cubed;

            if (x > n) {
                // If x exceeds n for the current a, further increases in b will also exceed n. Stop inner loop.
                break;
            }

            // Record the sum
            sumCounts.set(x, (sumCounts.get(x) || 0) + 1);
        }
    }

    // Collect all sums that appeared at least twice
    const goodIntegers = [];
    for (const [sum, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodIntegers.push(sum);
        }
    }

    // Sort the results in ascending order
    goodIntegers.sort((a, b) => a - b);

    return goodIntegers;
}

